import { Kernel } from '@microsoft/semantic-kernel';
import { KernelFunctionContext } from '@microsoft/semantic-kernel/core';

const kernel = Kernel.create();

// Detection in plugin invocation handler
function detectCrossPluginContamination(context: KernelFunctionContext): boolean {
  const memories = context.memory?.getRelevantMemories('default', 3) || [];
  const expectedDomains = ['weather', 'math', 'finance'];

  const pluginDomains = context.function?.metadata?.tags || [];

  for (const memory of memories) {
    const memoryTags = memory.metadata?.tags || [];
    const hasValidDomain = memoryTags.some(tag => 
      expectedDomains.some(domain => pluginDomains.includes(domain))
    );

    if (!hasValidDomain) {
      console.warn(`Cross-plugin contamination: ${memory.id}`);
      return true;
    }
  }
  return false;
}
