async function safeMemorySearch(collection: string, query: string) {
  const results = await memory.search(collection, query, {
    limit: 3,
    minRelevanceScore: 0.75,  // Enforce high relevance
    filter: undefined
  });

  return results.filter(r => r.relevance > 0.75);
