    def sanitize_context_for_plugin(context: ChatHistory, plugin_name: str) -> ChatHistory:
        sanitized = ChatHistory()
        allowed_roles = ['user', 'assistant']

        for content in context:
            if content.role in allowed_roles and len(content.content) < 2000:
                sanitized.add_user_message(content.content)

